const payload = $input.first().json;
const message = payload.messages?.[0];
const contact = payload.contacts?.[0];
if (!message) return [];
const phoneNumber = message.from || '';
const senderName = contact?.profile?.name || 'Cliente';
return [{ json: { phoneNumber, senderName, chatInput: message.text?.body || '[Multimedia]', sessionId: phoneNumber } }];

const agentOutput = $input.first().json.output || $input.first().json.text || '';
const openTag = "[LEAD_COMPLETE]";
const closeTag = "[/LEAD_COMPLETE]";
let cleanMessage = agentOutput;
let leadComplete = false;
let leadData = null;

if (agentOutput.includes(openTag) && agentOutput.includes(closeTag)) {
    const start = agentOutput.indexOf(openTag) + openTag.length;
    const end = agentOutput.indexOf(closeTag);
    const jsonPart = agentOutput.slice(start, end).trim();
    try {
        leadData = JSON.parse(jsonPart);
        const { nombre, email, telefono, presupuesto } = leadData;

        // VALIDACIÓN ESTRICTA: Ignorar si contiene puntos suspensivos o está vacío
        const isInvalid = (val) => !val || val.includes('...') || val.length < 2;

        if (!isInvalid(nombre) && !isInvalid(email) && email.includes('@')) {
            leadComplete = true;
        }
    } catch (e) {
        leadData = { error: "JSON inválido" };
    }
    cleanMessage = agentOutput.split(openTag)[0].trim();
}

return [{ 
    json: { 
        phoneNumber: $('Extract Message').item.json.phoneNumber, 
        cleanMessage, 
        leadComplete, 
        leadData 
    } 
}];
